.darma-loader-darma-custom-352 {color: var(--loader-color, #4f46e5);
  --loader-secondary-color: #a5b4fc;
  --loader-bg: #ffffff;
  display: inline-grid;
  width: 40px;
  aspect-ratio: 1;
  border-radius: 50%;
  background: repeating-conic-gradient(from 30deg,var(--loader-color, #4f46e5) 0 60deg,var(--loader-secondary-color, #a5b4fc) 0 120deg);
  animation: darma-loader-darma-custom-352-l9-0 3s linear infinite;
}.darma-loader-darma-custom-352:before,.darma-loader-darma-custom-352:after {content:"";
  grid-area: 1/1;
  border-radius: 50%;
  background: inherit;
  transform: rotate(0turn) translate(100%,0);
  animation: darma-loader-darma-custom-352-l9-1 3s linear infinite;
}.darma-loader-darma-custom-352:before {animation-delay: -1.5s;
}@keyframes darma-loader-darma-custom-352-l9-0 {to{rotate: -1turn}}@keyframes darma-loader-darma-custom-352-l9-1 {to{transform: rotate(1turn) translate(100%,0) rotate(1turn)}}

